import { TestingModule } from '@nestjs/testing';
import { DataSource, Repository } from 'typeorm';
import { createIntegrationTestModule, cleanDatabase } from './setup';
import { Category } from '../../src/entities/category.entity';
import { buildCategory } from '../factories/category.factory';
import { Product } from '../../src/entities/product.entity';
import { buildProduct } from '../factories/product.factory';

describe('Category Relationships', () => {
  let module: TestingModule;
  let dataSource: DataSource;
  let repository: Repository<Category>;

  beforeAll(async () => {
    module = await createIntegrationTestModule();
    dataSource = module.get(DataSource);
    repository = dataSource.getRepository(Category);
  });

  afterEach(async () => {
    await cleanDatabase(dataSource);
  });

  afterAll(async () => {
    await module.close();
  });

  describe('has_many products', () => {
    it('loads children via relation', async () => {
      const parentData = buildCategory();
      const parent = await repository.save(repository.create(parentData));

      const childRepo = dataSource.getRepository(Product);
      const childData = buildProduct({ categoryId: parent.id });
      await childRepo.save(childRepo.create(childData));

      const loaded = await repository.findOne({
        where: { id: parent.id } as Record<string, unknown>,
        relations: ['products'],
      });
      expect(loaded).not.toBeNull();
      expect(loaded!.products).toBeDefined();
      expect(loaded!.products.length).toBeGreaterThanOrEqual(1);
    });
  });
});
